import{_ as n,C as o,o as s,c as l,E as i,w as t,a as r,a0 as g}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Belgium Legal Rights","description":"Legal rights for transgender people in Belgium","frontmatter":{"layout":"doc","title":"Belgium Legal Rights","description":"Legal rights for transgender people in Belgium"},"headers":[],"relativePath":"europe/belgium/legal-rights.md","filePath":"europe/belgium/legal-rights.md","lastUpdated":null}'),d={name:"europe/belgium/legal-rights.md"};function c(h,e,u,m,p,f){const a=o("Badge");return s(),l("div",null,[i(a,{variant:"yellow"},{default:t(()=>[...e[0]||(e[0]=[r("Self-ID since 2018",-1)])]),_:1}),i(a,{variant:"green"},{default:t(()=>[...e[1]||(e[1]=[r("Hate Crime Protections",-1)])]),_:1}),e[2]||(e[2]=g('<h1 id="legal-rights-in-belgium" tabindex="-1">Legal Rights in Belgium <a class="header-anchor" href="#legal-rights-in-belgium" aria-label="Permalink to &quot;Legal Rights in Belgium&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Belgium adopted a self-declaration model for legal gender recognition in 2018, replacing the previous requirement for surgery and sterilisation. A trans person can change their legal gender on official documents by submitting a declaration at the civil registry office. Minors aged 16-17 can apply with parental consent; those under 16 require a court order.</p><p>No medical diagnosis, surgery, or hormone therapy is required. The process involves a simple administrative fee and typically takes a few weeks.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Legal name changes follow a simplified procedure for transgender people. You submit a request to the civil registry office along with your gender recognition declaration. The process costs approximately €50-100 and takes 1-3 months.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Belgium has strong anti-discrimination protections. Gender identity and gender expression are explicitly protected grounds in:</p><ul><li><strong>Employment</strong>: Hiring, promotion, termination</li><li><strong>Goods and services</strong>: Housing, healthcare, banking</li><li><strong>Education</strong>: All levels of schooling</li><li><strong>Social protection</strong>: Benefits and social security</li></ul><p>The Belgian Institute for Equality of Women and Men handles discrimination complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is explicitly recognised as an aggravated factor in hate crime prosecutions. Penalties for crimes motivated by transphobia can be doubled. Belgium has a dedicated hate crime reporting system through local police and the Institute for Equality.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://transgenderinfopunt.be/" target="_blank" rel="noreferrer">Transgender Infopunt</a> — Legal guidance</li><li><a href="https://igvm-iefh.belgium.be/" target="_blank" rel="noreferrer">Institute for Equality of Women and Men</a> — Discrimination complaints</li><li><a href="https://www.rainbowhouse.be/" target="_blank" rel="noreferrer">RainbowHouse Brussels</a> — LGBTQ+ legal support</li></ul>',14))])}const _=n(d,[["render",c]]);export{y as __pageData,_ as default};
